import{_ as a,o as i,c as e,a2 as t}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"2018年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2018年/核心总结.md","filePath":"01_letters/2018年/核心总结.md"}'),r={name:"01_letters/2018年/核心总结.md"};function o(h,l,u,n,d,s){return i(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="_2018年巴菲特致股东信核心总结" tabindex="-1">2018年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2018年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2018年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>GAAP净利润40亿美元，但包含206亿美元未实现投资损失（新会计准则导致）</li><li>营业利润248亿美元，比2016年增长41%</li><li>每股账面价值仅增长0.4%，市场价值增长2.8%，而标普500下跌4.4%</li><li>宣布不再以账面价值变化作为主要业绩指标</li></ul><h2 id="重大管理变动" tabindex="-1">重大管理变动 <a class="header-anchor" href="#重大管理变动" aria-label="Permalink to &quot;重大管理变动&quot;">​</a></h2><ul><li>Ajit Jain负责所有保险业务</li><li>Greg Abel负责所有非保险业务</li><li>管理效率显著提升，伯克希尔进入新时代</li></ul><h2 id="五大-树林-战略" tabindex="-1">五大&quot;树林&quot;战略 <a class="header-anchor" href="#五大-树林-战略" aria-label="Permalink to &quot;五大&quot;树林&quot;战略&quot;">​</a></h2><p>巴菲特首次明确提出伯克希尔由五大树林构成：</p><h3 id="第一树林-非保险业务" tabindex="-1">第一树林：非保险业务 <a class="header-anchor" href="#第一树林-非保险业务" aria-label="Permalink to &quot;第一树林：非保险业务&quot;">​</a></h3><ul><li>税前利润208亿美元，增长24%</li><li>BNSF和伯克希尔能源合计贡献93亿美元</li><li>资本支出145亿美元创纪录（89%投资美国）</li></ul><h3 id="第二树林-股票投资组合" tabindex="-1">第二树林：股票投资组合 <a class="header-anchor" href="#第二树林-股票投资组合" aria-label="Permalink to &quot;第二树林：股票投资组合&quot;">​</a></h3><ul><li>年末市值1728亿美元</li><li>收到股息38亿美元</li><li>五大持仓留存收益68亿美元</li><li>苹果成最大持仓（403亿美元）</li></ul><h3 id="第三树林-共同控制企业" tabindex="-1">第三树林：共同控制企业 <a class="header-anchor" href="#第三树林-共同控制企业" aria-label="Permalink to &quot;第三树林：共同控制企业&quot;">​</a></h3><ul><li>包括卡夫亨氏（26.7%）、Pilot Flying J（38.6%）等</li><li>税后利润约13亿美元</li></ul><h3 id="第四树林-现金与固定收益" tabindex="-1">第四树林：现金与固定收益 <a class="header-anchor" href="#第四树林-现金与固定收益" aria-label="Permalink to &quot;第四树林：现金与固定收益&quot;">​</a></h3><ul><li>持有1120亿美元国库券和现金等价物</li><li>另有200亿美元固定收益工具</li><li>承诺永远保持至少200亿美元现金缓冲</li></ul><h3 id="第五树林-保险浮存金" tabindex="-1">第五树林：保险浮存金 <a class="header-anchor" href="#第五树林-保险浮存金" aria-label="Permalink to &quot;第五树林：保险浮存金&quot;">​</a></h3><ul><li>浮存金达1227亿美元（历史新高）</li><li>过去16年中15年实现承保利润</li><li>2018年承保利润20亿美元</li></ul><h2 id="税收改革影响" tabindex="-1">税收改革影响 <a class="header-anchor" href="#税收改革影响" aria-label="Permalink to &quot;税收改革影响&quot;">​</a></h2><ul><li>企业税率从35%降至21%</li><li>政府所持&quot;AA股&quot;（税收权）40%免费返还伯克希尔</li><li>非保险业务税后利润增长47%</li></ul><h2 id="投资理念更新" tabindex="-1">投资理念更新 <a class="header-anchor" href="#投资理念更新" aria-label="Permalink to &quot;投资理念更新&quot;">​</a></h2><ul><li>2018年买入430亿美元股票，仅卖出190亿美元</li><li>股票投资价值超过收购整体企业</li><li>关注营业利润而非GAAP利润的波动</li><li>坚持不发布月度财报，不给华尔街&quot;交数字&quot;</li></ul><h2 id="重要收购与投资" tabindex="-1">重要收购与投资 <a class="header-anchor" href="#重要收购与投资" aria-label="Permalink to &quot;重要收购与投资&quot;">​</a></h2><ul><li>增持苹果至2.55亿股（市值403亿美元）</li><li>新增持摩根大通5066万股</li><li>继续增持美国银行至9.19亿股</li></ul><h2 id="美国顺风-理论" tabindex="-1">&quot;美国顺风&quot;理论 <a class="header-anchor" href="#美国顺风-理论" aria-label="Permalink to &quot;&quot;美国顺风&quot;理论&quot;">​</a></h2><ul><li>巴菲特投资77周年纪念</li><li>114.75美元投入标普500将增长至60.7万美元（税前）</li><li>国债增加400倍，但美国企业依然创造惊人回报</li><li>黄金回报仅4200美元，不及股票1%</li><li>强调美国两党合作成就国家繁荣</li></ul><h2 id="回购政策" tabindex="-1">回购政策 <a class="header-anchor" href="#回购政策" aria-label="Permalink to &quot;回购政策&quot;">​</a></h2><ul><li>明确将以低于内在价值的价格回购股票</li><li>回购使留下的股东每股内在价值增加</li><li>承诺提供充分信息让股东做出明智决定</li></ul><h2 id="关键数据" tabindex="-1">关键数据 <a class="header-anchor" href="#关键数据" aria-label="Permalink to &quot;关键数据&quot;">​</a></h2><ul><li>非保险业务税前利润：208亿美元</li><li>保险浮存金：1227亿美元</li><li>现金储备：1320亿美元（含固定收益）</li><li>递延税款：505亿美元（其中147亿来自未实现投资收益）</li><li>折旧费用：84亿美元（低估真实经济成本）</li></ul><h2 id="文化与治理" tabindex="-1">文化与治理 <a class="header-anchor" href="#文化与治理" aria-label="Permalink to &quot;文化与治理&quot;">​</a></h2><ul><li>无全公司预算，不设季度目标</li><li>拒绝&quot;调整后EBITDA&quot;等虚假指标</li><li>警告管理层为满足华尔街预期而粉饰业绩的危险</li><li>强调为股东合伙人工作的理念</li></ul><h2 id="股东大会" tabindex="-1">股东大会 <a class="header-anchor" href="#股东大会" aria-label="Permalink to &quot;股东大会&quot;">​</a></h2><ul><li>2019年5月4日举行</li><li>继续由Yahoo网络直播</li><li>强调奥马哈作为&quot;资本主义摇篮&quot;的地位</li></ul>',33)])])}const b=a(r,[["render",o]]);export{c as __pageData,b as default};
